- 'lighter than a bag of sugar' refers to weighing less than 5 kilograms;
- 'wandered further than a typical day's journey' refers to wandering a distance greater than 10 units;
- 'achievements in research studies shine brighter than a thousand stars' refers to the value of study results being greater than 1000.

sql:
SELECT COUNT(cat_id) 
FROM cats 
WHERE coat = 'tabby' AND sex = 'female';

SELECT cat_id, location_id 
FROM cat_locations
WHERE wander_dist > 0.035;

SELECT cat_id, last_seen_date
FROM cats
WHERE last_seen_date >= date('now', '-30 days');

SELECT coat, COUNT(*) AS num_of_cats
FROM cats
GROUP BY coat;

SELECT tnr_status
FROM cat_tnr
WHERE cat_id = 1 AND program_id = 1;

SELECT COUNT(*)
FROM cats
WHERE fixed = 1 AND roamer = 1 AND health_status = 'good';

SELECT COUNT(*) 
FROM cats 
WHERE coat = 'tabby';

SELECT COUNT(DISTINCT cats.cat_id) AS "Number of Cats Studied", AVG(cats.age) AS "Average Age"
FROM cats
JOIN cat_studies ON cats.cat_id = cat_studies.cat_id;

SELECT cat_id, age, coat, sex
FROM cats
WHERE age = (
  SELECT MAX(age) FROM cats
);

SELECT cat_id
FROM cats
WHERE last_seen_date = (SELECT MAX(last_seen_date) FROM cats);

